                </ResponsiveContainer>
              </Card>
              <Card>
                <STitle>DATA SCIENCE PIPELINE</STitle>
                {[
                  ["1. Data Collection","Traffic.csv + TrafficTwoMonth.csv","#3b82f6"],
                  ["2. Preprocessing","Parse time ‚Üí hour, minute features","#a78bfa"],
